15	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
16	const COMPONENT_UNIT_PREMIUM = 25;
17	const COMPONENT_BLOCK_PREMIUM = 60;
18	const COMPONENT_BLOCK_SIZE = 3;
19	
20	const basePremium = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
21	
22	const componentBlockBase = (count: number): number =>
23	  count === COMPONENT_BLOCK_SIZE
24	    ? COMPONENT_BLOCK_PREMIUM
25	    : count * COMPONENT_UNIT_PREMIUM;
26	
27	const policyBaseFor = (items: Item[]): number => {
28	  const componentCounts = new Map<string, number>();
29	  let mainBase = 0;
30	  for (const item of items) {
31	    if (COMPONENT_TYPES.has(item.type)) {
32	      componentCounts.set(item.type, (componentCounts.get(item.type) ?? 0) + 1);
33	    } else {
34	      mainBase += basePremium(item);
35	    }
36	  }
37	  let componentBase = 0;
38	  for (const count of componentCounts.values()) {
39	    componentBase += componentBlockBase(count);
40	  }
41	  return mainBase + componentBase;
42	};
43	
44	const quotePremium = (items: Item[]): number => {
45	  const policyBase = policyBaseFor(items);
46	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
47	  return Math.ceil(policyBase + firstInsuranceSurcharge) + PROCESSING_FEE;
48	};
49	
50	export const runScenario = (input: unknown): unknown => {
51	  const scenario = input as Scenario;
52	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
53	  return { results };
54	};
